package com.example.socialloginmodule

data class User(
    val id: String,
    val name: String?,
    val email: String?,
    val provider: String, // "facebook" or "google"
    val idToken: String? = null // For Google, useful for backend authentication
)

// SocialLoginCallback.kt
package com.example.socialloginmodule

interface SocialLoginCallback {
    fun onLoginSuccess(user: User)
    fun onLoginFailure(error: Throwable)
    fun onLoginCancel()
}

// SocialLoginManager.kt
package com.example.socialloginmodule

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.util.Log
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.FacebookSdk
import com.facebook.GraphRequest
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import org.json.JSONException

class SocialLoginManager(private val context: Context, private val callback: SocialLoginCallback) {

    companion object {
        private const val RC_SIGN_IN_GOOGLE = 9001
        private const val TAG = "SocialLoginManager"

        // Hardcoded credentials for public beta testing as requested
        // WARNING: Storing secrets directly in client-side code is INSECURE for production.
        // These should be moved to a secure server, environment variables, or other secure storage
        // methods after beta testing.
        const val FACEBOOK_APP_ID = "123456789012345"
        const val FACEBOOK_APP_SECRET = "abcdef1234567890abcdef1234567890" // Not directly used by client-side Android SDK for login
        const val GOOGLE_WEB_CLIENT_ID = "1234-abcdef.apps.googleusercontent.com"
        const val GOOGLE_CLIENT_SECRET = "GOCSpx-AbCdEf123456" // Not directly used by client-side Android SDK for login
    }

    private val facebookCallbackManager: CallbackManager by lazy { CallbackManager.Factory.create() }
    private val googleSignInClient: GoogleSignInClient

    init {
        // Initialize Facebook SDK
        FacebookSdk.setApplicationId(FACEBOOK_APP_ID)
        FacebookSdk.sdkInitialize(context.applicationContext)

        // Configure Google Sign-In options
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(GOOGLE_WEB_CLIENT_ID) // Request ID token for backend authentication
            .requestEmail()
            .requestProfile()
            .build()
        googleSignInClient = GoogleSignIn.getClient(context, gso)

        // Register Facebook Login Callback
        LoginManager.getInstance().registerCallback(facebookCallbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                Log.d(TAG, "Facebook Login Success: ${result.accessToken.token}")
                val request = GraphRequest.newMeRequest(result.accessToken) { jsonObject, _ ->
                    try {
                        val id = jsonObject?.getString("id")
                        val name = jsonObject?.getString("name")
                        val email = jsonObject?.getString("email")
                        if (id != null) {
                            val user = User(id, name, email, "facebook")
                            callback.onLoginSuccess(user)
                        } else {
                            callback.onLoginFailure(Exception("Facebook user ID not found."))
                        }
                    } catch (e: JSONException) {
                        Log.e(TAG, "Error parsing Facebook user data", e)
                        callback.onLoginFailure(e)
                    }
                }
                val parameters = Bundle()
                parameters.putString("fields", "id,name,email,picture.type(large)") // Request necessary fields
                request.parameters = parameters
                request.executeAsync()
            }

            override fun onCancel() {
                Log.d(TAG, "Facebook Login Cancelled")
                callback.onLoginCancel()
            }

            override fun onError(error: FacebookException) {
                Log.e(TAG, "Facebook Login Error: ${error.message}", error)
                callback.onLoginFailure(error)
            }
        })
    }

    /**
     * Initiates the Facebook login flow.
     * @param activity The calling activity.
     */
    fun loginWithFacebook(activity: Activity) {
        LoginManager.getInstance().logInWithReadPermissions(activity, listOf("public_profile", "email"))
    }

    /**
     * Initiates the Google Sign-In flow.
     * @param activity The calling activity.
     */
    fun loginWithGoogle(activity: Activity) {
        val signInIntent = googleSignInClient.signInIntent
        activity.startActivityForResult(signInIntent, RC_SIGN_IN_GOOGLE)
    }

    /**
     * Must be called from the calling Activity's onActivityResult method.
     * @return true if the event was handled by the social login manager, false otherwise.
     */
    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        // Handle Facebook login results
        if (facebookCallbackManager.onActivityResult(requestCode, resultCode, data)) {
            return true
        }

        // Handle Google Sign-In results
        if (requestCode == RC_SIGN_IN_GOOGLE) {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            try {
                val account = task.getResult(ApiException::class.java)
                if (account != null) {
                    Log.d(TAG, "Google Login Success: ${account.displayName}")
                    val user = User(
                        id = account.id ?: account.email ?: "unknown_google_id",
                        name = account.displayName,
                        email = account.email,
                        provider = "google",
                        idToken = account.idToken
                    )
                    callback.onLoginSuccess(user)
                } else {
                    callback.onLoginFailure(Exception("GoogleSignInAccount is null."))
                }
            } catch (e: ApiException) {
                Log.e(TAG, "Google Sign-In failed with code: ${e.statusCode}, message: ${e.message}", e)
                if (e.statusCode == com.google.android.gms.common.api.CommonStatusCodes.CANCELED) {
                    callback.onLoginCancel()
                } else {
                    callback.onLoginFailure(e)
                }
            } catch (e: Exception) {
                Log.e(TAG, "Google Sign-In unexpected error: ${e.message}", e)
                callback.onLoginFailure(e)
            }
            return true
        }
        return false
    }

    /**
     * Logs out the currently signed-in user from both Facebook and Google.
     */
    fun logout() {
        LoginManager.getInstance().logOut()
        Log.d(TAG, "Facebook logout complete.")

        googleSignInClient.signOut().addOnCompleteListener {
            Log.d(TAG, "Google Sign out complete.")
        }
        googleSignInClient.revokeAccess().addOnCompleteListener {
            Log.d(TAG, "Google Revoke access complete.")
        }
    }
}

// LoginActivity.kt
package com.example.socialloginmodule

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class LoginActivity : AppCompatActivity(), SocialLoginCallback {

    private lateinit var socialLoginManager: SocialLoginManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login) // Assuming you have activity_login.xml layout

        socialLoginManager = SocialLoginManager(this, this)

        val facebookLoginButton: Button = findViewById(R.id.btn_login_facebook)
        val googleLoginButton: Button = findViewById(R.id.btn_login_google)

        facebookLoginButton.setOnClickListener {
            socialLoginManager.loginWithFacebook(this)
        }

        googleLoginButton.setOnClickListener {
            socialLoginManager.loginWithGoogle(this)
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        // Pass the activity result to the social login manager
        socialLoginManager.onActivityResult(requestCode, resultCode, data)
    }

    override fun onLoginSuccess(user: User) {
        val message = "Login Success! Provider: ${user.provider}, Name: ${user.name}, Email: ${user.email}, ID: ${user.id}"
        Log.d("LoginActivity", message)
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()

        // TODO: Navigate to your main application activity here
        // For example:
        // val intent = Intent(this, MainActivity::class.java)
        // startActivity(intent)
        // finish()
    }

    override fun onLoginFailure(error: Throwable) {
        val message = "Login Failed: ${error.message}"
        Log.e("LoginActivity", message, error)
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }

    override fun onLoginCancel() {
        Log.d("LoginActivity", "Login Cancelled by user")
        Toast.makeText(this, "Login Cancelled", Toast.LENGTH_SHORT).show()
    }
}

